package main

import (
	"fmt"
	"net/http"
	"text/template"
)

type comment struct {
	Name  string
	Text  string
	Image []byte
}

func main() {
	http.HandleFunc("/", showComments)
	http.ListenAndServe(":8080", nil)
}

func showComments(w http.ResponseWriter, r *http.Request) {
	cmts := []*comment{
		&comment{Name: "John Doe", Text: "This is a comment!", Image: []byte{}},
		&comment{Name: "Jane Smith", Text: "This <b>is</b> a comment with basic formatting!", Image: []byte{}},
	}

	tmpl, err := template.ParseFiles("index.html")
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}

	if err := tmpl.Execute(w, cmts); err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
	}
}

func mainLayout(cmt []*comment) string {
	template.Must(template.ParseFiles("layout.html"))
	output := ""
	for _, comment := range cmt {
		output += `<p>{{.Name}}: <i>Image not loaded</i></p>`
		output += fmt.Sprintf("<p><b>%s</b> said:</p>", comment.Name)
		output += fmt.Sprintf("<p style=\"border-left:solid 3px grey;\">%s</p>", comment.Text)
	}
	return output
}